102	  };
103	
104	  const simpleTextWithTooltip = (text?: string, color?: string, child?: JSX.Element, forcedSize?: Size) => {
105	    if (text) {
106	      return (
107	        <TextContent
108	          className={`field-text ${forcedSize || size} netobserv-no-child-margin`}
109	          data-test={`field-text-${text}`}
110	        >
111	          <Text className="record-field-value" component={TextVariants.p} style={{ color }}>
112	            {text}
113	          </Text>
