147	
148	  const kubeObjContent = (
149	    value: string | undefined,
150	    kind: string | undefined,
151	    ns: string | undefined,
152	    forcedSize?: Size
153	  ) => {
154	    // Note: namespace is not mandatory here (e.g. Node objects)
155	    if (value && kind) {
156	      return (
157	        <div data-test={`field-resource-${kind}.${ns}.${value}`} className="force-truncate">
158	          {resourceIconText(value, kind, ns, forcedSize)}
