161	      );
162	    }
163	    return undefined;
164	  };
165	
166	  const kubeTooltip = (value: string, kind: string, ns: string | undefined) => {
167	    return (
168	      <TextContent className="record-field-tooltip netobserv-no-child-margin">
169	        {ns && (
170	          <>
171	            <Text component={TextVariants.h4}>{t('Namespace')}</Text>
172	            <Text component={TextVariants.p}>{ns}</Text>
173	          </>
174	        )}
175	        <Text component={TextVariants.h4}>{kind}</Text>
176	        <Text component={TextVariants.p}>{value}</Text>
177	      </TextContent>
178	    );
179	  };
180	
181	  const kindContent = (kind: 'Namespace' | 'Node', value?: string, forcedSize?: Size) => {
182	    if (value) {
183	      return (
184	        <div data-test={`field-kind-${kind}.${value}`} className="force-truncate">
185	          {resourceIconText(value, kind, undefined, forcedSize)}
186	          <TextContent className="record-field-tooltip netobserv-no-child-margin">
