404	          }
405	        }
406	        return singleContainer(child);
407	      }
408	      case ColumnsId.icmptype: {
409	        let child = emptyText();
410	        if (typeof value === 'number' && !isNaN(value)) {
411	          const proto = Number(flow.fields.Proto);
412	          if (isValidICMPProto(proto)) {
413	            const type = getICMPType(proto, value as ICMPAllTypesValues);
414	            if (type && detailed) {
415	              child = clickableContent(type.name, type.description || '', getICMPDocUrl(proto));
416	            } else {
417	              child = simpleTextWithTooltip(type?.name || String(value))!;
418	            }
419	          } else {
420	            child = errorTextValue(
421	              String(value),
422	              t('ICMP type provided but protocol is {{proto}}', { proto: formatProtocol(proto, t) })
423	            );
424	          }
425	        }
426	        return singleContainer(child);
427	      }
428	      case ColumnsId.icmpcode: {
429	        let child = emptyText();
430	        if (typeof value === 'number' && !isNaN(value)) {
431	          const proto = Number(flow.fields.Proto);
432	          const typez = Number(flow.fields.IcmpType) as ICMPAllTypesValues;
433	          if (isValidICMPProto(proto)) {
434	            const code = getICMPCode(proto, typez, value);
435	            if (code && detailed) {
436	              child = clickableContent(code.name, code.description || '', getICMPDocUrl(proto));
437	            } else {
438	              child = simpleTextWithTooltip(code?.name || String(value))!;
439	            }
440	          } else {
441	            child = errorTextValue(
442	              String(value),
443	              t('ICMP code provided but protocol is {{proto}}', { proto: formatProtocol(proto, t) })
444	            );
445	          }
446	        }
447	        return singleContainer(child);
448	      }
449	      case ColumnsId.nodedir:
450	      case ColumnsId.ifdirs: {
451	        if (Array.isArray(value)) {
452	          return nthContainer(
453	            value.map(dir => simpleTextWithTooltip(getDirectionDisplayString(String(dir) as FlowDirection, t))),
454	            true,
455	            false,
456	            isTable,
457	            multiLineSize
458	          );
459	        }
460	        return singleContainer(simpleTextWithTooltip(getDirectionDisplayString(String(value) as FlowDirection, t)));
461	      }
462	      case ColumnsId.interfaces: {
463	        if (Array.isArray(value)) {
464	          return nthContainer(
465	            value.map(iName => simpleTextWithTooltip(String(iName))),
466	            true,
467	            false,
468	            isTable,
469	            multiLineSize
470	          );
471	        }
472	        return singleContainer(simpleTextWithTooltip(String(value)));
473	      }
474	      case ColumnsId.udns: {
475	        if (Array.isArray(value)) {
476	          return nthContainer(
477	            value
478	              .map(iName => String(iName))
479	              .filter(iName => iName !== '')
480	              .map(iName => simpleTextWithTooltip(iName)),
481	            true,
482	            false,
483	            isTable
484	          );
485	        }
486	        return singleContainer(simpleTextWithTooltip(String(value)));
487	      }
488	      case ColumnsId.flowdirints: {
489	        if (
490	          flow.fields.Interfaces &&
491	          flow.fields.IfDirections &&
492	          Array.isArray(flow.fields.Interfaces) &&
