  1	import { ResourceIcon, ResourceLink } from '@openshift-console/dynamic-plugin-sdk';
  2	import { Button, Content, ContentVariants, Flex, FlexItem, Popover, Tooltip } from '@patternfly/react-core';
  3	import { GlobeAmericasIcon } from '@patternfly/react-icons';
  4	import * as React from 'react';
  5	import { useTranslation } from 'react-i18next';
  6	import { FlowDirection, getDirectionDisplayString, Record } from '../../../api/ipfix';
  7	import { Column, ColumnsId, getFullColumnName, isKubeObj, KubeObj } from '../../../utils/columns';
  8	import { dateFormatter, getFormattedDate, timeMSFormatter, utcDateTimeFormatter } from '../../../utils/datetime';
  9	import { dnsCodesNames, dnsErrorsValues, getDNSErrorDescription, getDNSRcodeDescription } from '../../../utils/dns';
 10	import { getDSCPDocUrl, getDSCPServiceClassDescription, getDSCPServiceClassName } from '../../../utils/dscp';
 11	import { formatDurationAboveMillisecond, formatDurationAboveNanosecond } from '../../../utils/duration';
 12	import { getICMPCode, getICMPDocUrl, getICMPType, ICMPAllTypesValues, isValidICMPProto } from '../../../utils/icmp';
 13	import { DropCausesNames, getDropCauseDescription, getDropCauseDocUrl } from '../../../utils/pkt-drop';
 14	import { formatPort } from '../../../utils/port';
 15	import { formatProtocol, getProtocolDocUrl } from '../../../utils/protocol';
 16	import { getFlagsList, getTCPFlagsDocUrl } from '../../../utils/tcp-flags';
 17	import { Link } from '../../../utils/url';
 18	import { Size } from '../../dropdowns/table-display-dropdown';
 19	import { FilterAddIcon, FilterRemoveIcon, FilterToggleOffIcon, FilterToggleOnIcon } from '../../icons';
 20	import './record-field.css';
 21	
 22	export type RecordFieldFilter = {
 23	  type: 'filter' | 'switch';
 24	  onClick: () => void;
 25	  isDelete: boolean;
 26	};
 27	
 28	export const maxArrayIndex = 2;
 29	
 30	export type FlexValue = 'flexDefault' | 'flexNone' | 'flex_1' | 'flex_2' | 'flex_3' | 'flex_4';
 31	export type FlexWrapValue = 'wrap' | 'wrapReverse' | 'nowrap';
 32	
 33	export interface RecordFieldProps {
 34	  allowPktDrops: boolean;
 35	  flow: Record;
 36	  column: Column;
 37	  size?: Size;
 38	  useLinks: boolean;
 39	  filter?: RecordFieldFilter;
 40	  detailed?: boolean;
 41	  isDark?: boolean;
 42	}
 43	
 44	export const RecordField: React.FC<RecordFieldProps> = ({
 45	  allowPktDrops,
 46	  flow,
 47	  column,
 48	  size,
 49	  filter,
 50	  useLinks,
 51	  detailed,
 52	  isDark
 53	}) => {
 54	  const { t } = useTranslation('plugin__netobserv-plugin');
 55	  const multiLineSize = size === 'l' ? 'm' : 's';
 56	
 57	  const errorTextValue = (value: string, text: string) => {
 58	    return (
 59	      <div className="record-field-flex">
 60	        <Tooltip
 61	          content={[
 62	            <Content component={ContentVariants.p} className="record-field-value co-nowrap" key="co-error-text">
 63	              {text}
 64	            </Content>
 65	          ]}
 66	        >
 67	          <Content
 68	            component={ContentVariants.p}
 69	            style={{ color: isDark ? '#C9190B' : '#A30000' }}
 70	            className="record-field-flex"
 71	          >
 72	            {value}
 73	          </Content>
 74	        </Tooltip>
 75	      </div>
 76	    );
 77	  };
 78	
 79	  const emptyText = (errorText?: string) => {
 80	    if (errorText) {
 81	      return errorTextValue(t('n/a'), errorText);
 82	    }
 83	    return (
 84	      <Content component="p" className="record-field-flex text-muted record-field-value">
 85	        {t('n/a')}
 86	      </Content>
 87	    );
 88	  };
 89	
 90	  const moreText = (count: number) => {
 91	    return <Content component="p" className="record-field-flex record-field-value">{`${count} ${t('more')}...`}</Content>;
 92	  };
 93	
 94	  const emptyDnsErrorText = () => {
 95	    return emptyText(
 96	      flow.fields.DnsErrno
 97	        ? `${t('DNS Error')} ${flow.fields.DnsErrno}: ${getDNSErrorDescription(
 98	            flow.fields.DnsErrno as dnsErrorsValues
 99	          )}`
100	        : undefined
101	    );
102	  };
103	
104	  const simpleTextWithTooltip = (text?: string, color?: string, child?: JSX.Element, forcedSize?: Size) => {
105	    if (text) {
106	      return (
107	        <Content
108	          className={`field-text ${forcedSize || size} netobserv-no-child-margin`}
109	          data-test={`field-text-${text}`}
110	        >
111	          <Content className="record-field-value" component={ContentVariants.p} style={{ color }}>
112	            {text}
113	          </Content>
114	          <Content component={ContentVariants.p} className="record-field-tooltip">
115	            {text}
116	          </Content>
117	          {child}
118	        </Content>
119	      );
120	    }
121	    return undefined;
122	  };
123	
124	  const resourceIconText = (value: string, kind: string, ns?: string, forcedSize?: Size) => {
125	    return (
126	      //force ResourceLink when ResourceIcon is not defined (ie OCP < 4.12)
127	      !ResourceIcon || useLinks ? (
128	        <ResourceLink className={size} inline={true} kind={kind} name={value} namespace={ns} />
129	      ) : (
130	        <Content className={`co-resource-item ${forcedSize || size} netobserv-no-child-margin`}>
131	          <ResourceIcon kind={kind} />
132	          <Content component={ContentVariants.p} className="co-resource-item__resource-name" data-test-id={value}>
133	            {value}
134	          </Content>
135	        </Content>
136	      )
137	    );
138	  };
139	
140	  const kubeObjContainer = (k: KubeObj) => {
141	    const main = kubeObjContent(k.name, k.kind, k.namespace, multiLineSize);
142	    if (k.showNamespace && k.namespace) {
143	      return doubleContainer(main, kindContent('Namespace', k.namespace, multiLineSize), false, true, 'm');
144	    }
145	    return singleContainer(main);
146	  };
147	
148	  const kubeObjContent = (
149	    value: string | undefined,
150	    kind: string | undefined,
151	    ns: string | undefined,
152	    forcedSize?: Size
153	  ) => {
154	    // Note: namespace is not mandatory here (e.g. Node objects)
155	    if (value && kind) {
156	      return (
157	        <div data-test={`field-resource-${kind}.${ns}.${value}`} className="force-truncate">
158	          {resourceIconText(value, kind, ns, forcedSize)}
159	          {kubeTooltip(value, kind, ns)}
160	        </div>
161	      );
162	    }
163	    return undefined;
164	  };
165	
166	  const kubeTooltip = (value: string, kind: string, ns: string | undefined) => {
167	    return (
168	      <Content className="record-field-tooltip netobserv-no-child-margin">
169	        {ns && (
170	          <>
171	            <Content component={ContentVariants.h4}>{t('Namespace')}</Content>
172	            <Content component={ContentVariants.p}>{ns}</Content>
173	          </>
174	        )}
175	        <Content component={ContentVariants.h4}>{kind}</Content>
176	        <Content component={ContentVariants.p}>{value}</Content>
177	      </Content>
178	    );
179	  };
180	
181	  const kindContent = (kind: 'Namespace' | 'Node', value?: string, forcedSize?: Size) => {
182	    if (value) {
183	      return (
184	        <div data-test={`field-kind-${kind}.${value}`} className="force-truncate">
185	          {resourceIconText(value, kind, undefined, forcedSize)}
186	          <Content className="record-field-tooltip netobserv-no-child-margin">
187	            <Content component={ContentVariants.h4}>{t(kind)}</Content>
188	            <Content component={ContentVariants.p}>{value}</Content>
189	          </Content>
190	        </div>
191	      );
192	    }
193	    return undefined;
194	  };
195	
196	  const dateTimeContent = (date: Date | undefined) => {
197	    if (!date) {
198	      return emptyText();
199	    }
200	
201	    const fullDateText = getFormattedDate(date, utcDateTimeFormatter);
202	    const dateText = getFormattedDate(date, dateFormatter) + ',';
203	    const timeText = getFormattedDate(date, timeMSFormatter);
204	    return singleContainer(
205	      <Flex data-test={`field-date-${dateText}-${timeText}`} className="record-field-date">
206	        <FlexItem className="record-field-date-icon-container">
207	          <GlobeAmericasIcon className="record-field-date-icon" />
208	        </FlexItem>
209	        <FlexItem>
210	          <Tooltip
211	            content={[
212	              <Content component={ContentVariants.p} className="co-nowrap" key="co-timestamp">
213	                {fullDateText}
214	              </Content>
215	            ]}
216	          >
217	            <Content className={`datetime ${size} netobserv-no-child-margin`}>
218	              <Content component={ContentVariants.p}>{dateText}</Content>{' '}
219	              <Content component={ContentVariants.p} className="text-muted">
220	                {timeText}
221	              </Content>
222	            </Content>
223	          </Tooltip>
224	        </FlexItem>
225	      </Flex>
226	    );
227	  };
228	
229	  const nthContainer = (
230	    children: (JSX.Element | undefined)[],
231	    asChild = true,
232	    childIcon = true,
233	    truncate?: boolean,
234	    forcedSize?: Size,
235	    className = ''
236	  ) => {
237	    return (
238	      <Flex className={`record-field-flex-container ${forcedSize || size} ${className}`} flex={{ default: 'flex_1' }}>
239	        {children.length > 0 ? (
240	          children
241	            .filter((_c, i) => !truncate || i < maxArrayIndex)
242	            .map((c, i) => {
243	              const child = c ? c : emptyText();
244	              if (i > 0 && asChild && childIcon) {
245	                const arrow = <span className="child-arrow">{'↪'}</span>;
246	                return (
247	                  <React.Fragment key={i}>
248	                    {sideBySideContainer(arrow, child, 'flexNone', 'flex_1', 'nowrap')}
249	                  </React.Fragment>
250	                );
251	              }
252	              return <React.Fragment key={i}>{child}</React.Fragment>;
253	            })
254	        ) : (
255	          <Content component="p" className="text-muted record-field-value">
256	            {t('n/a')}
257	          </Content>
258	        )}
259	        {truncate && children.length > maxArrayIndex && moreText(children.length - maxArrayIndex)}
260	      </Flex>
261	    );
262	  };
263	
264	  const doubleContainer = (
265	    child1?: JSX.Element,
266	    child2?: JSX.Element,
267	    asChild = true,
268	    childIcon = true,
269	    forcedSize?: Size
270	  ) => {
271	    return nthContainer([child1, child2], asChild, childIcon, false, forcedSize);
272	  };
273	
274	  const sideBySideContainer = (
275	    leftElement?: JSX.Element,
276	    rightElement?: JSX.Element,
277	    leftFlex: FlexValue = 'flex_1',
278	    rightFlex: FlexValue = 'flex_1',
279	    wrap: FlexWrapValue = 'wrap'
280	  ) => {
281	    return (
282	      <Flex direction={{ default: 'row' }} flex={{ default: 'flex_1' }} flexWrap={{ default: wrap }}>
283	        <FlexItem className="side-by-side" flex={{ default: leftFlex }}>
284	          {leftElement || emptyText()}
285	        </FlexItem>
286	        <FlexItem className="side-by-side" flex={{ default: rightFlex }}>
287	          {rightElement || emptyText()}
288	        </FlexItem>
289	      </Flex>
290	    );
291	  };
292	
293	  const singleContainer = (child?: JSX.Element) => {
294	    return <div className={`record-field-content ${size}`}>{child ? child : emptyText()}</div>;
295	  };
296	
297	  const clickableContent = (text: string, content: string, docUrl?: string) => {
298	    return (
299	      <Popover
300	        headerContent={text}
301	        bodyContent={content}
302	        footerContent={
303	          docUrl ? (
304	            <Button
305	              variant="link"
306	              component={(props: React.FunctionComponent) => (
307	                <Link {...props} target="_blank" to={{ pathname: docUrl }} />
308	              )}
309	            >
310	              {t('Show related documentation')}
311	            </Button>
312	          ) : undefined
313	        }
314	      >
315	        <Button
316	          icon={<Content component={ContentVariants.h4}>{text}</Content>}
317	          variant="plain"
318	          className="record-field-value-popover-button"
319	        />
320	      </Popover>
321	    );
322	  };
323	
324	  const content = (c: Column, isTable: boolean) => {
325	    if (!c.value) {
326	      // Value function not configured
327	      return emptyText();
328	    }
329	    const value = c.value(flow);
330	    switch (c.id) {
331	      case ColumnsId.collectiontime:
332	      case ColumnsId.starttime:
333	      case ColumnsId.endtime:
334	        return dateTimeContent(typeof value === 'number' && !isNaN(value) ? new Date(value) : undefined);
335	      case ColumnsId.collectionlatency:
336	      case ColumnsId.duration:
337	      case ColumnsId.rttTime:
338	        return singleContainer(
339	          typeof value === 'number' && !isNaN(value)
340	            ? simpleTextWithTooltip(
341	                c.id === ColumnsId.rttTime
342	                  ? formatDurationAboveNanosecond(value as number)
343	                  : formatDurationAboveMillisecond(value as number)
344	              )
345	            : undefined
346	        );
347	      case ColumnsId.port:
348	        return doubleContainer(
349	          simpleTextWithTooltip(flow.fields.SrcPort ? formatPort(flow.fields.SrcPort) : ''),
350	          simpleTextWithTooltip(flow.fields.DstPort ? formatPort(flow.fields.DstPort) : '')
351	        );
352	      case ColumnsId.srcport:
353	      case ColumnsId.dstport: {
354	        return singleContainer(simpleTextWithTooltip(value ? formatPort(value as number) : ''));
355	      }
356	      case ColumnsId.proto: {
357	        if (typeof value === 'number' && !isNaN(value)) {
358	          const docUrl = getProtocolDocUrl();
359	          const protocolName = formatProtocol(value as number, t);
360	          return singleContainer(
361	            detailed
362	              ? clickableContent(protocolName, `${t('Value')}: ${value}`, docUrl)
363	              : simpleTextWithTooltip(protocolName)
364	          );
365	        } else {
366	          return singleContainer(emptyText());
367	        }
368	      }
369	      case ColumnsId.dscp: {
370	        let child = emptyText();
371	        if (typeof value === 'number' && !isNaN(value)) {
372	          const serviceClassName = getDSCPServiceClassName(value);
373	          if (serviceClassName && detailed) {
374	            child = clickableContent(
375	              serviceClassName,
376	              `${t('Value')}: ${value} ${t('Examples')}: ${getDSCPServiceClassDescription(value)}`,
377	              getDSCPDocUrl()
378	            );
379	          } else {
380	            child = simpleTextWithTooltip(serviceClassName || String(value))!;
381	          }
382	        }
383	        return singleContainer(child);
384	      }
385	      case ColumnsId.tcpflags:
386	      case ColumnsId.dropflags: {
387	        let child = emptyText();
388	        if (Array.isArray(value) && value.length > 0) {
389	          const flags = getFlagsList(value as string[]);
390	          const joined = value.join(', ');
391	          if (detailed) {
392	            let description = `${t('Value')}: ${value}`;
393	            if (flags.length === 1) {
394	              description += '. ' + flags[0].description;
395	            } else if (flags.length > 1) {
396	              description +=
397	                '. ' +
398	                t('The flow contains packets with various flags: ') +
399	                flags.map(f => f.name + ' (' + f.description + ')').join('; ');
400	            }
401	            child = clickableContent(joined, description, getTCPFlagsDocUrl());
402	          } else {
403	            child = simpleTextWithTooltip(joined)!;
404	          }
405	        }
406	        return singleContainer(child);
407	      }
408	      case ColumnsId.icmptype: {
409	        let child = emptyText();
410	        if (typeof value === 'number' && !isNaN(value)) {
411	          const proto = Number(flow.fields.Proto);
412	          if (isValidICMPProto(proto)) {
413	            const type = getICMPType(proto, value as ICMPAllTypesValues);
414	            if (type && detailed) {
415	              child = clickableContent(type.name, type.description || '', getICMPDocUrl(proto));
416	            } else {
417	              child = simpleTextWithTooltip(type?.name || String(value))!;
418	            }
419	          } else {
420	            child = errorTextValue(
421	              String(value),
422	              t('ICMP type provided but protocol is {{proto}}', { proto: formatProtocol(proto, t) })
423	            );
424	          }
425	        }
426	        return singleContainer(child);
427	      }
428	      case ColumnsId.icmpcode: {
429	        let child = emptyText();
430	        if (typeof value === 'number' && !isNaN(value)) {
431	          const proto = Number(flow.fields.Proto);
432	          const typez = Number(flow.fields.IcmpType) as ICMPAllTypesValues;
433	          if (isValidICMPProto(proto)) {
434	            const code = getICMPCode(proto, typez, value);
435	            if (code && detailed) {
436	              child = clickableContent(code.name, code.description || '', getICMPDocUrl(proto));
437	            } else {
438	              child = simpleTextWithTooltip(code?.name || String(value))!;
439	            }
440	          } else {
441	            child = errorTextValue(
442	              String(value),
443	              t('ICMP code provided but protocol is {{proto}}', { proto: formatProtocol(proto, t) })
444	            );
445	          }
446	        }
447	        return singleContainer(child);
448	      }
449	      case ColumnsId.nodedir:
450	      case ColumnsId.ifdirs: {
451	        if (Array.isArray(value)) {
452	          return nthContainer(
453	            value.map(dir => simpleTextWithTooltip(getDirectionDisplayString(String(dir) as FlowDirection, t))),
454	            true,
455	            false,
456	            isTable,
457	            multiLineSize
458	          );
459	        }
460	        return singleContainer(simpleTextWithTooltip(getDirectionDisplayString(String(value) as FlowDirection, t)));
461	      }
462	      case ColumnsId.interfaces: {
463	        if (Array.isArray(value)) {
464	          return nthContainer(
465	            value.map(iName => simpleTextWithTooltip(String(iName))),
466	            true,
467	            false,
468	            isTable,
469	            multiLineSize
470	          );
471	        }
472	        return singleContainer(simpleTextWithTooltip(String(value)));
473	      }
474	      case ColumnsId.udns: {
475	        if (Array.isArray(value)) {
476	          return nthContainer(
477	            value
478	              .map(iName => String(iName))
479	              .filter(iName => iName !== '')
480	              .map(iName => simpleTextWithTooltip(iName)),
481	            true,
482	            false,
483	            isTable
484	          );
485	        }
486	        return singleContainer(simpleTextWithTooltip(String(value)));
487	      }
488	      case ColumnsId.flowdirints: {
489	        if (
490	          flow.fields.Interfaces &&
491	          flow.fields.IfDirections &&
492	          Array.isArray(flow.fields.Interfaces) &&
493	          Array.isArray(flow.fields.IfDirections) &&
494	          flow.fields.Interfaces.length === flow.fields.IfDirections.length
495	        ) {
496	          return nthContainer(
497	            flow.fields.Interfaces.map((iName, i) =>
498	              sideBySideContainer(
499	                simpleTextWithTooltip(iName, undefined, undefined, multiLineSize),
500	                simpleTextWithTooltip(
501	                  getDirectionDisplayString(String(flow.fields.IfDirections![i]) as FlowDirection, t),
502	                  undefined,
503	                  undefined,
504	                  multiLineSize
505	                )
506	              )
507	            ),
508	            true,
509	            false,
510	            isTable,
511	            undefined,
512	            'flowdirints'
513	          );
514	        } else {
515	          return singleContainer(emptyText(t('Invalid data provided. Check JSON for details.')));
516	        }
517	      }
518	      case ColumnsId.packets:
519	      case ColumnsId.bytes:
520	        //show both sent / dropped counts
521	        if (Array.isArray(value)) {
522	          let droppedText = t('dropped');
523	          let child: JSX.Element | undefined = undefined;
524	          if (detailed && c.id === ColumnsId.packets && flow.fields.PktDropLatestDropCause) {
525	            droppedText = t('dropped by');
526	            child = clickableContent(
527	              flow.fields.PktDropLatestDropCause,
528	              getDropCauseDescription(flow.fields.PktDropLatestDropCause as DropCausesNames),
529	              getDropCauseDocUrl(flow.fields.PktDropLatestDropCause as DropCausesNames)
530	            );
531	          }
532	
533	          const sentCount = value.length >= 1 && value[0] ? String(value[0]) : String(0);
534	          const droppedCount = allowPktDrops && value.length >= 2 && value[1] ? String(value[1]) : undefined;
535	          return doubleContainer(
536	            simpleTextWithTooltip(
537	              detailed ? `${sentCount} ${c.name.toLowerCase()} ${t('sent')}` : sentCount,
538	              allowPktDrops ? (isDark ? '#3E8635' : '#1E4F18') : undefined,
539	              undefined,
540	              multiLineSize
541	            ),
542	            droppedCount ? (
543	              simpleTextWithTooltip(
544	                detailed ? `${droppedCount} ${c.name.toLowerCase()} ${droppedText}` : droppedCount,
545	                isDark ? '#C9190B' : '#A30000',
546	                child,
547	                multiLineSize
548	              )
549	            ) : (
550	              <></>
551	            ),
552	            true,
553	            false
554	          );
555	        } else {
556	          return singleContainer(
557	            simpleTextWithTooltip(detailed ? `${String(value)} ${c.name.toLowerCase()} ${t('sent')}` : String(value))
558	          );
559	        }
560	      case ColumnsId.dropbytes:
561	      case ColumnsId.droppackets:
562	        const droppedText = t('dropped');
563	        const droppedCount = String(value);
564	        return singleContainer(
565	          simpleTextWithTooltip(
566	            detailed ? `${droppedCount} ${c.name.toLowerCase()} ${droppedText}` : droppedCount,
567	            isDark ? '#C9190B' : '#A30000'
568	          )
569	        );
570	      case ColumnsId.dnsid: {
571	        return singleContainer(
572	          typeof value === 'number' && !isNaN(value) ? simpleTextWithTooltip(String(value)) : emptyDnsErrorText()
573	        );
574	      }
575	      case ColumnsId.dnslatency: {
576	        return singleContainer(
577	          typeof value === 'number' && !isNaN(value)
578	            ? simpleTextWithTooltip(formatDurationAboveMillisecond(value as number))
579	            : emptyDnsErrorText()
580	        );
581	      }
582	      case ColumnsId.dnsresponsecode: {
583	        return singleContainer(
584	          typeof value === 'string' && value.length
585	            ? simpleTextWithTooltip(detailed ? `${value}: ${getDNSRcodeDescription(value as dnsCodesNames)}` : value)
586	            : emptyDnsErrorText()
587	        );
588	      }
589	      case ColumnsId.dnserrno: {
590	        return singleContainer(
591	          typeof value === 'number' && !isNaN(value)
592	            ? simpleTextWithTooltip(
593	                detailed && value ? `${value}: ${getDNSErrorDescription(value as dnsErrorsValues)}` : String(value)
594	              )
595	            : emptyText()
596	        );
597	      }
598	      case ColumnsId.udn: {
599	        const id = value as string;
600	        let child: JSX.Element | undefined;
601	        // TODO: define how to split the UDN ID
602	        // an alternative could be to use `calculated: kubeObject(K8S_UDN_Type,K8S_UDN_Namespace,K8S_UDN_Name,0)`
603	        // from config within 3 separated fields
604	        if (id.includes('.')) {
605	          const parts = id.split('.');
606	          child = kubeObjContent(parts[1], 'UserDefinedNetwork', parts[0]);
607	        } else {
608	          child = kubeObjContent(id, 'ClusterUserDefinedNetwork', undefined);
609	        }
610	        return singleContainer(child);
611	      }
612	      default:
613	        if (value === undefined) {
614	          return emptyText();
615	        }
616	        if (Array.isArray(value) && value.length) {
617	          // we can only show two values properly with containers
618	          if (value.length === 2) {
619	            const contents = value.map(v =>
620	              isKubeObj(v) ? kubeObjContainer(v) : simpleTextWithTooltip(String(v), undefined, undefined, multiLineSize)
621	            );
622	            return doubleContainer(contents[0], contents[1], undefined, undefined, multiLineSize);
623	          }
624	          // else we will show values as single joigned string
625	          return singleContainer(simpleTextWithTooltip(value.map(v => String(v)).join(', ')));
626	        } else if (value && isKubeObj(value)) {
627	          return kubeObjContainer(value);
628	        } else {
629	          return singleContainer(simpleTextWithTooltip(String(value)));
630	        }
631	    }
632	  };
633	  return filter ? (
634	    <Flex className={`record-field-flex-container`} flex={{ default: 'flex_1' }}>
635	      <FlexItem className={'record-field-flex'} flex={{ default: 'flex_1' }}>
636	        {content(column, false)}
637	      </FlexItem>
638	      <FlexItem>
639	        <Tooltip
640	          content={
641	            filter.type === 'filter'
642	              ? filter.isDelete
643	                ? t('Remove {{name}} filter', { name: getFullColumnName(column) })
644	                : t('Filter on {{name}}', { name: getFullColumnName(column) })
645	              : t('Switch {{name}} option', { name: getFullColumnName(column) })
646	          }
647	        >
648	          <Button
649	            variant="link"
650	            aria-label="Filter"
651	            onClick={filter.onClick}
652	            icon={
653	              filter.type === 'filter' ? (
654	                filter.isDelete ? (
655	                  <FilterRemoveIcon />
656	                ) : (
657	                  <FilterAddIcon />
658	                )
659	              ) : filter.isDelete ? (
660	                <FilterToggleOffIcon />
661	              ) : (
662	                <FilterToggleOnIcon />
663	              )
664	            }
665	          />
666	        </Tooltip>
667	      </FlexItem>
668	    </Flex>
669	  ) : (
670	    content(column, true)
671	  );
672	};
673	
674	export default RecordField;

